// ── HTTP helper ───────────────────────────────────────────────────────────────
function sbRequest(method, urlPath, body) {
  return new Promise((resolve, reject) => {
    const u   = new URL(SUPABASE + urlPath);
    const str = body ? JSON.stringify(body) : null;
    const req = https.request({
      hostname: u.hostname, path: u.pathname + u.search, method,
      headers: {
        apikey: ANON_KEY, Authorization: `Bearer ${ANON_KEY}`,
        Accept: 'application/json',
        ...(str ? { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(str) } : {}),
        ...(method === 'POST' ? { Prefer: 'resolution=merge-duplicates,return=minimal' } : {}),
      },
    }, res => {
      let d = ''; res.on('data', c => d += c);
      res.on('end', () => {
        try { resolve({ status: res.statusCode, body: d ? JSON.parse(d) : null }); }
        catch (_) { resolve({ status: res.statusCode, body: d }); }
      });
    });
    req.on('error', reject);
    if (str) req.write(str);
    req.end();
  });
}

// ── Fetch content map: norm(url_full) → { id, url_full } ─────────────────────
async function fetchContentMap() {
  const map = new Map();
  let offset = 0;
  while (true) {
    const r = await sbRequest('GET', `/rest/v1/content?select=id,url_full&limit=1000&offset=${offset}`);
    if (!Array.isArray(r.body)) throw new Error('Content fetch failed: ' + JSON.stringify(r.body).slice(0, 200));
    for (const row of r.body) {
      if (row.url_full) map.set(row.url_full.replace(/\/$/, '').toLowerCase(), row);
    }
    if (r.body.length < 1000) break;
    offset += 1000;
  }
  console.log(`  Content map: ${map.size} rows`);
  return map;
}

// ── Normalise a URL for matching ──────────────────────────────────────────────
function norm(url) { return url.replace(/\/$/, '').toLowerCase(); }

// ── Build GA4 lookup for one week: normPath → [users, dur] ───────────────────
// GA4 paths like "/" or "/slug/" → convert to full URL norm
function buildGA4Map(snapshotDate) {
  const raw = GA4[snapshotDate] || {};
  const m = new Map();
  for (const [path, val] of Object.entries(raw)) {
    const full = norm(WP_BASE + path);
    m.set(full, val);
  }
  return m;
}

// ── Read and parse a GSC file ─────────────────────────────────────────────────
function readGSC(ts) {
  const fp = `${GSC_DIR}/${GSC_PFX}${ts}.txt`;
  if (!fs.existsSync(fp)) throw new Error(`GSC file not found: ${fp}`);
  const raw = fs.readFileSync(fp, 'utf8');
  // File may be plain JSON or wrapped in tool-result envelope
  let parsed;
  try { parsed = JSON.parse(raw); } catch (_) {
    const m = raw.match(/\{[\s\S]*\}/);
    if (!m) throw new Error(`Cannot parse GSC file ${ts}`);
    parsed = JSON.parse(m[0]);
  }
  // Handle both { rows: [...] } and array directly
  const rows = Array.isArray(parsed) ? parsed : (parsed.rows || []);
  return rows;
}

// ── Build all performance rows ────────────────────────────────────────────────
function buildRows(contentMap) {
  // Map: normUrl → { snapshot → gsc row }
  // Then enrich with GA4, compute deltas, output flat array

  // Per-url, per-week data keyed by snapshot date (sorted order)
  const byUrl = new Map(); // normUrl → Map<snapshot, rowData>

  for (const week of WEEKS) {
    const { snapshot, ts } = week;
    let gscRows;
    try { gscRows = readGSC(ts); }
    catch (e) { console.error(`  ⚠ ${e.message} — skipping week ${snapshot}`); continue; }

    const ga4Map = buildGA4Map(snapshot);
    console.log(`  ${snapshot}: ${gscRows.length} GSC rows, ${ga4Map.size} GA4 paths`);

    for (const gsc of gscRows) {
      const url = norm(gsc.page || gsc.url || '');
      if (!url) continue;

      const dbRow = contentMap.get(url);
      if (!dbRow) continue; // not in content table, skip

      const ga4 = ga4Map.get(url);

      if (!byUrl.has(url)) byUrl.set(url, new Map());
      byUrl.get(url).set(snapshot, {
        url_full:      dbRow.url_full,
        content_id:    dbRow.id,
        snapshot_date: snapshot,
        gsc_clicks:    gsc.clicks      ?? null,
        gsc_impressions: gsc.impressions ?? null,
        gsc_position:  gsc.position    != null ? Math.round(gsc.position * 100) / 100 : null,
        gsc_ctr:       gsc.ctr         != null ? Math.round((parseFloat(String(gsc.ctr).replace('%','')) / 100) * 100000) / 100000 : null,
        ga_users:      ga4 ? ga4[0] : null,
        ga_avg_engagement_sec: ga4 ? Math.round(ga4[1] * 100) / 100 : null,
        clicks_delta: null, impressions_delta: null,
        position_delta: null, users_delta: null,
      });
    }
  }

  // Compute deltas week-over-week
  const allRows = [];
  const orderedSnapshots = WEEKS.map(w => w.snapshot);

  for (const [, weekMap] of byUrl) {
    const snapshots = orderedSnapshots.filter(s => weekMap.has(s));
    for (let i = 0; i < snapshots.length; i++) {
      const row  = weekMap.get(snapshots[i]);
      if (i > 0) {
        const prev = weekMap.get(snapshots[i - 1]);
        row.clicks_delta      = (row.gsc_clicks      != null && prev.gsc_clicks      != null) ? row.gsc_clicks      - prev.gsc_clicks      : null;
        row.impressions_delta = (row.gsc_impressions  != null && prev.gsc_impressions  != null) ? row.gsc_impressions  - prev.gsc_impressions  : null;
        row.position_delta    = (row.gsc_position     != null && prev.gsc_position     != null) ? Math.round((row.gsc_position - prev.gsc_position) * 100) / 100 : null;
        row.users_delta       = (row.ga_users         != null && prev.ga_users         != null) ? row.ga_users         - prev.ga_users         : null;
      }
      allRows.push(row);
    }
  }

  return allRows;
}

// ── Upsert in batches ─────────────────────────────────────────────────────────
async function upsertAll(rows) {
  const total = rows.length;
  let done = 0, errors = 0;
  for (let i = 0; i < rows.length; i += BATCH_SIZE) {
    const batch = rows.slice(i, i + BATCH_SIZE);
    const batchNo = Math.floor(i / BATCH_SIZE) + 1;
    const batchCount = Math.ceil(rows.length / BATCH_SIZE);
    process.stdout.write(`  Batch ${batchNo}/${batchCount} (${batch.length} rows)... `);
    const r = await sbRequest(
      'POST',
      '/rest/v1/performance?on_conflict=url_full,snapshot_date',
      batch
    );
    if (r.status >= 200 && r.status < 300) {
      done += batch.length;
      console.log('OK');
    } else {
      errors++;
      console.log(`ERROR ${r.status}: ${JSON.stringify(r.body).slice(0, 200)}`);
    }
    await new Promise(res => setTimeout(res, 150));
  }
  console.log(`\n  ${done}/${total} rows upserted, ${errors} batch errors`);
}

// ── Main ──────────────────────────────────────────────────────────────────────
async function main() {
  console.log('=== PERFORMANCE TABLE IMPORT ===\n');

  console.log('Step 1: Fetching content map from Supabase...');
  const contentMap = await fetchContentMap();

  console.log('\nStep 2: Building performance rows (GSC + GA4)...');
  const rows = buildRows(contentMap);
  console.log(`\n  Total rows to upsert: ${rows.length}`);

  if (!rows.length) { console.log('Nothing to insert.'); return; }

  console.log('\nStep 3: Upserting to performance table...');
  await upsertAll(rows);

  console.log('\n=== COMPLETE ===');
}

main().catch(e => { console.error('Fatal:', e.message, e.stack); process.exit(1); });
